arguments.file_text:
@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (_userRating ?? 0) ? "filled" : (star <= (int)Math.Round(AverageRating) ? "average" : ""))"
              @onclick="() => Rate(star)"
              role="button"
              title="@star star(s)">
            &#9733;
        </span>
    }
    <span class="rating-text">
        @if (_userRating.HasValue)
        {
            <text>You rated @_userRating stars!</text>
        }
        else
        {
            <text>@AverageRating.ToString("F1") (@TotalRatings ratings)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }
    [Parameter] public EventCallback<int> OnRate { get; set; }

    private int? _userRating;

    private async Task Rate(int stars)
    {
        if (_userRating.HasValue) return;
        _userRating = stars;
        await OnRate.InvokeAsync(stars);
    }
}

.star-rating {
    display: flex;
    align-items: center;
    gap: 0.15rem;
}

.star {
    font-size: 1.8rem;
    color: #ccc;
    cursor: pointer;
    transition: color 0.15s, transform 0.1s;
    user-select: none;
}

.star:hover {
    transform: scale(1.2);
}

.star.filled {
    color: #f5a623;
}

.star.average {
    color: #ddd06a;
}

.rating-text {
    margin-left: 0.6rem;
    font-size: 0.9rem;
    color: #666;
}

@page "/"
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="text-center mb-4">
    <h1>🍽️ Recipe Community</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2 class="mb-3">Browse by Category</h2>

<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <h3 class="card-title">
                        <span class="category-icon">@GetCategoryIcon(category)</span>
                        @category
                    </h3>
                    <p class="card-text text-muted">
                        @RecipeService.GetRecipesByCategory(category).Count recipe(s)
                    </p>
                    <a href="category/@category" class="btn btn-outline-primary">Browse Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🥡",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍴"
    };
}

@page "/category/{CategoryName}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            @for (int i = 1; i <= 5; i++)
                            {
                                <span style="color: @(i <= (int)Math.Round(recipe.AverageRating) ? "#f5a623" : "#ccc")">&#9733;</span>
                            }
                            <small class="text-muted">@recipe.AverageRating.ToString("F1") (@recipe.TotalRatings)</small>
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe")</PageTitle>

@if (_recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
