@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (_userRating ?? 0) ? "filled" : (star <= (int)Math.Round(AverageRating) ? "average" : ""))"
              @onclick="() => Rate(star)"
              role="button"
              title="@star star(s)">
            &#9733;
        </span>
    }
    <span class="rating-text">
        @if (_userRating.HasValue)
        {
            <text>You rated @_userRating stars!</text>
        }
        else
        {
            <text>@AverageRating.ToString("F1") (@TotalRatings ratings)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }
    [Parameter] public EventCallback<int> OnRate { get; set; }

    private int? _userRating;

    private async Task Rate(int stars)
    {
        if (_userRating.HasValue) return;
        _userRating = stars;
        await OnRate.InvokeAsync(stars);
    }
}

