toolArgs.file_text:
@page "/"
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="text-center mb-4">
    <h1>🍽️ Recipe Community</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2 class="mb-3">Browse by Category</h2>

<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <h3 class="card-title">
                        <span class="category-icon">@GetCategoryIcon(category)</span>
                        @category
                    </h3>
                    <p class="card-text text-muted">
                        @RecipeService.GetRecipesByCategory(category).Count recipe(s)
                    </p>
                    <a href="category/@category" class="btn btn-outline-primary">Browse Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🥡",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍴"
    };
}

@page "/category/{CategoryName}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            @for (int i = 1; i <= 5; i++)
                            {
                                <span style="color: @(i <= (int)Math.Round(recipe.AverageRating) ? "#f5a623" : "#ccc")">&#9733;</span>
                            }
                            <small class="text-muted">@recipe.AverageRating.ToString("F1") (@recipe.TotalRatings)</small>
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe")</PageTitle>

@if (_recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h1>@_recipe.Title</h1>
    <p class="lead">@_recipe.Description</p>

    <StarRating RecipeId="@_recipe.Id"
                AverageRating="@_recipe.AverageRating"
                TotalRatings="@_recipe.TotalRatings"
                OnRate="HandleRating" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">📝 Steps</h5></div>
                <div class="card-body">
                    <ol class="mb-0">
                        @foreach (var step in _recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@_submission.Title</strong>" has been added.</p>
        <a href="recipe/@_newRecipeId" class="btn btn-primary btn-sm">View Your Recipe</a>
        <button class="btn btn-outline-secondary btn-sm ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label" for="title">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="_submission.Title" placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="category">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="_submission.Category">
                        <option value="">-- Select a category --</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label class="form-label" for="ingredients">Ingredients (one per line)</label>
                    <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="_submission.Ingredients"
                                   placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="steps">Steps (one per line)</label>
                    <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="_submission.Steps"
                                   placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Bake for 30 minutes." />
                </div>

                <button type="submit" class="btn btn-success"
                        disabled="@(!IsValid)">
                    Submit Recipe
                </button>
            </div>
        </div>
    </EditForm>
}

@code {
    private RecipeSubmission _submission = new();
    private bool _submitted;
    private int _newRecipeId;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(_submission.Title) &&
        !string.IsNullOrWhiteSpace(_submission.Category) &&
        !string.IsNullOrWhiteSpace(_submission.Ingredients) &&
        !string.IsNullOrWhiteSpace(_submission.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        var recipe = RecipeService.AddRecipe(_submission);
        _newRecipeId = recipe.Id;
        _submitted = true;
    }

    private void Reset()
    {
        _submission = new();
        _submitted = false;
    }
}

